import { Component } from '@angular/core';
import { ActivatedRoute, Router } from '@angular/router';
import { SponsorshipRequest } from 'src/app/core/models/request.model';
import { AuthService } from 'src/app/core/services/auth.service';
import { RequestService } from 'src/app/core/services/request.service';

@Component({
  selector: 'app-admin-details',
  templateUrl: './admin-details.component.html',
  styleUrls: ['./admin-details.component.css']
})
export class AdminDetailsComponent {
  requestId: number = 0;
  request: SponsorshipRequest | null = null;
  isLoading = false;
  isSubmitting = false;

  constructor(
    private route: ActivatedRoute,
    private requestService: RequestService,
    private authService: AuthService,
    private router: Router
  ) { }

  ngOnInit() {
    this.requestId = Number(this.route.snapshot.paramMap.get('id'));
    this.loadRequestDetails();
  }

  loadRequestDetails() {
    this.isLoading = true;
    this.requestService.getRequestById(this.requestId).subscribe({
      next: (request) => {
        request.status = this.mapStatusToString(Number(request.status));
        this.request = new SponsorshipRequest(request);
        this.isLoading = false;
      },
      error: (error) => {
        console.error('Error:', error);
        this.isLoading = false;
        alert('Error loading request details');
      }
    });
  }

  mapStatusToString(status: number): string {
    const statusMap: { [key: number]: string } = {
      1: 'Draft',
      2: 'PendingManager',
      3: 'PendingFinance',
      4: 'Approved',
      5: 'Rejected',
      6: 'Cancelled'
    };
    return statusMap[status] || 'Draft';
  }



  goBack() {
    this.router.navigate(['/admin/all-requests']);
  }
}
<div class="container mt-4">
  <div class="card" *ngIf="!isLoading && request">
    <div class="card-header">
      <h3>Request Details</h3>
      <span class="badge" [class]="request.getStatusClass()">
        {{ request.getStatusText() }}
      </span>
    </div>

    <div class="card-body">
      <div class="row">
        <div class="col-md-6">
          <p><strong>Title:</strong> {{ request.title }}</p>
          <p><strong>Department:</strong> {{ request.department }}</p>
          <p><strong>Event Name:</strong> {{ request.eventName }}</p>
          <p><strong>Event Date:</strong> {{ request.eventDate | date }}</p>
        </div>
        <div class="col-md-6">
          <p><strong>Amount:</strong> ${{ request.requestedAmount }}</p>
          <p><strong>Status:</strong> {{ request.getStatusText() }}</p>
          <p><strong>Created:</strong> {{ request.createdAt | date }}</p>
        </div>
      </div>

      <div class="row mt-3">
        <div class="col-12">
          <p><strong>Justification:</strong></p>
          <p>{{ request.justification }}</p>
        </div>
      </div>
      <div class="row mt-3" *ngIf="request.managerRemarks?.trim()">
        <div class="col-12">
          <p><strong>Manager Remarks:</strong></p>
          <p>{{ request.managerRemarks }}</p>
        </div>
      </div>
       <div class="row mt-3" *ngIf="request.financeRemarks?.trim()">
        <div class="col-12">
          <p><strong>Finance Remarks:</strong></p>
          <p>{{ request.financeRemarks }}</p>
        </div>
      </div>
    </div>

    <div class="card-footer">
      <button class="btn btn-secondary" (click)="goBack()">Back</button>
    </div>
  </div>
</div>
